import { test, expect } from '@playwright/test';

test('Amazon SG monitor search and back navigation', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/');

  // 2. Search for "monitor".
  const searchBox = page.locator('input#twotabsearchtextbox');
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('monitor');
  await page.getByRole('button', { name: 'Go' }).click();

  // 3. Click first product.
  const firstProduct = page.locator('div.s-main-slot div[data-component-type="s-search-result"]').first().locator('h2 a');
  await expect(firstProduct).toBeVisible({ timeout: 10000 });
  await firstProduct.click();

  // 4. Click browser back button.
  await page.goBack();

  // 5. Validate search results page is displayed.
  // Wait for search results main slot to be visible
  const searchResults = page.locator('div.s-main-slot');
  await expect(searchResults).toBeVisible({ timeout: 10000 });
  // Optionally, check that the search box still contains 'monitor'
  await expect(searchBox).toHaveValue('monitor');

  // 6. Close browser.
  // (Playwright test runner handles browser close automatically)
});
